+describe("patchAllowlistUsersInConfigEntries", () => {
+  it("supports canonicalization strategy for nested users", () => {
+    const entries = {
+      alpha: { users: ["Alice", "111", "Bob"] },
+      beta: { users: ["*"] },
+    };
+    const resolvedMap = new Map([
+      ["Alice", { input: "Alice", resolved: true, id: "111" }],
